+    /// Load hybrid CSR outlier data from file and enable hybrid mode
+    /// This enables 30 TPS inference by using Q2_K base weights + FP16 sparse corrections
+    /// Returns true if hybrid mode was successfully enabled
+    pub fn loadHybridCSR(self: *Self, csr_path: []const u8) !bool {
+        const file = std.fs.cwd().openFile(csr_path, .{}) catch |err| {
+            log.warn("Could not open CSR file: {s} ({s})", .{ csr_path, @errorName(err) });
+            return false;
+        };
+        defer file.close();
+
+        // Verify magic
+        var magic: [8]u8 = undefined;
+        _ = file.readAll(&magic) catch return false;
+        if (!std.mem.eql(u8, &magic, "ZELL_CSR")) {
+            log.warn("Invalid CSR file magic", .{});
+            return false;
+        }
+
+        var version: u32 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&version));
+        if (version != 1) {
+            log.warn("Unsupported CSR version: {d}", .{version});
+            return false;
+        }
+
+        var tensor_count: u32 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&tensor_count));
+
+        log.info("Loading {d} CSR tensors for hybrid mode...", .{tensor_count});
+
+        var loaded_count: u32 = 0;
+        for (0..tensor_count) |_| {
+            // Read tensor name
+            var name_len: u16 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&name_len));
+            var name_buf: [128]u8 = undefined;
+            _ = try file.readAll(name_buf[0..name_len]);
+            const name = name_buf[0..name_len];
+
+            // Parse tensor name to get layer, projection, expert
+            // Format: blk.{layer}.ffn_{gate|up|down}.{expert}.weight
+            const layer_expert = self.parseTensorName(name) orelse continue;
+            const buf_idx = layer_expert.layer * 8 + layer_expert.expert;
+
+            // Read CSR metadata
+            var rows: u32 = undefined;
+            var cols: u32 = undefined;
+            var nnz: u32 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&rows));
+            _ = try file.readAll(std.mem.asBytes(&cols));
+            _ = try file.readAll(std.mem.asBytes(&nnz));
+
+            // Read and upload row_ptr
+            const row_ptr_size = (rows + 1) * @sizeOf(u32);
+            const row_ptr_buf = try self.allocator.alloc(u8, row_ptr_size);
+            defer self.allocator.free(row_ptr_buf);
+            _ = try file.readAll(row_ptr_buf);
+
+            // Read and upload col_idx
+            const col_idx_size = nnz * @sizeOf(u16);
+            const col_idx_buf = try self.allocator.alloc(u8, col_idx_size);
+            defer self.allocator.free(col_idx_buf);
+            _ = try file.readAll(col_idx_buf);
+
+            // Read and upload values
+            const values_size = nnz * @sizeOf(f16);
+            const values_buf = try self.allocator.alloc(u8, values_size);
+            defer self.allocator.free(values_buf);
+            _ = try file.readAll(values_buf);
+
+            // Create Metal buffers
+            const row_ptr_metal = objc.deviceNewBufferWithBytes(
+                self.device,
+                row_ptr_buf.ptr,
+                row_ptr_size,
+                objc.MTLResourceStorageModeShared,
+            ) orelse continue;
+
+            const col_idx_metal = objc.deviceNewBufferWithBytes(
+                self.device,
+                col_idx_buf.ptr,
+                col_idx_size,
+                objc.MTLResourceStorageModeShared,
+            ) orelse continue;
+
+            const values_metal = objc.deviceNewBufferWithBytes(
+                self.device,
+                values_buf.ptr,
+                values_size,
+                objc.MTLResourceStorageModeShared,
+            ) orelse continue;
+
+            // Store in appropriate array based on projection type
+            switch (layer_expert.proj) {
+                .gate => {
+                    self.hybrid_csr_gate_row_ptr[buf_idx] = row_ptr_metal;
+                    self.hybrid_csr_gate_col_idx[buf_idx] = col_idx_metal;
+                    self.hybrid_csr_gate_values[buf_idx] = values_metal;
+                },
+                .up => {
+                    self.hybrid_csr_up_row_ptr[buf_idx] = row_ptr_metal;
+                    self.hybrid_csr_up_col_idx[buf_idx] = col_idx_metal;
+                    self.hybrid_csr_up_values[buf_idx] = values_metal;
+                },
+                .down => {
+                    self.hybrid_csr_down_row_ptr[buf_idx] = row_ptr_metal;
+                    self.hybrid_csr_down_col_idx[buf_idx] = col_idx_metal;
+                    self.hybrid_csr_down_values[buf_idx] = values_metal;
+                },
+            }
+            loaded_count += 1;
+        }
+
+        if (loaded_count > 0) {
+            self.hybrid_mode_enabled = true;
+            log.info("Hybrid mode enabled: {d} CSR tensors loaded", .{loaded_count});
+            return true;
+        }
+        return false;
+    }
+
+    const ProjectionType = enum { gate, up, down };
+    const LayerExpert = struct {
+        layer: u8,
+        expert: u8,
+        proj: ProjectionType,
+    };
+
+    fn parseTensorName(self: *Self, name: []const u8) ?LayerExpert {
+        _ = self;
+        // Format: blk.{layer}.ffn_{gate|up|down}.{expert}.weight
+        if (!std.mem.startsWith(u8, name, "blk.")) return null;
+
+        var iter = std.mem.splitScalar(u8, name, '.');
+        _ = iter.next(); // "blk"
+        const layer_str = iter.next() orelse return null;
+        const proj_str = iter.next() orelse return null;
+        const expert_str = iter.next() orelse return null;
+
+        const layer = std.fmt.parseInt(u8, layer_str, 10) catch return null;
+        const expert = std.fmt.parseInt(u8, expert_str, 10) catch return null;
+
+        const proj: ProjectionType = if (std.mem.eql(u8, proj_str, "ffn_gate"))
+            .gate
+        else if (std.mem.eql(u8, proj_str, "ffn_up"))
+            .up
+        else if (std.mem.eql(u8, proj_str, "ffn_down"))
+            .down
+        else
+            return null;
+
+        return LayerExpert{ .layer = layer, .expert = expert, .proj = proj };
+    }
+
